import httpx
import time
import logging
from typing import Any, Optional, Set

logger = logging.getLogger(__name__)

RETRYABLE_STATUS_CODES = {429, 500, 502, 503, 504}

class HttpClient:
    def __init__(self, base_url: str, timeout: float = 30.0,
                 max_retries: int = 3, base_delay: float = 1.0,
                 retryable_statuses: Optional[Set[int]] = None):
        self.base_url = base_url
        self.timeout = timeout
        self.max_retries = max_retries
        self.base_delay = base_delay
        self.retryable_statuses = retryable_statuses or RETRYABLE_STATUS_CODES

    def request(self, method: str, path: str, **kwargs) -> httpx.Response:
        url = f'{self.base_url}{path}'
        last_response = None
        for attempt in range(self.max_retries + 1):
            response = httpx.request(method, url, timeout=self.timeout, **kwargs)
            if response.status_code not in self.retryable_statuses:
                return response
            last_response = response
            if attempt < self.max_retries:
                delay = self.base_delay * (2 ** attempt)
                logger.warning(
                    'Retryable status %d on %s %s, retrying in %.1fs (attempt %d/%d)',
                    response.status_code, method, path, delay, attempt + 1, self.max_retries
                )
                time.sleep(delay)
        return last_response

    def get(self, path: str, **kwargs) -> httpx.Response:
        return self.request('GET', path, **kwargs)

    def post(self, path: str, **kwargs) -> httpx.Response:
        return self.request('POST', path, **kwargs)

@patch('src.http_client.time.sleep')
@patch('src.http_client.httpx.request')
def test_retries_on_503(mock_request, mock_sleep):
    mock_request.side_effect = [
        MagicMock(status_code=503),
        MagicMock(status_code=503),
        MagicMock(status_code=200),
    ]
    client = HttpClient('http://api.test', max_retries=3, base_delay=0.1)
    resp = client.get('/flaky')
    assert resp.status_code == 200
    assert mock_request.call_count == 3
    assert mock_sleep.call_count == 2  # slept before retry 2 and 3


@patch('src.http_client.time.sleep')
@patch('src.http_client.httpx.request')
def test_retries_on_429(mock_request, mock_sleep):
    mock_request.side_effect = [
        MagicMock(status_code=429),
        MagicMock(status_code=200),
    ]
    client = HttpClient('http://api.test', max_retries=3, base_delay=0.1)
    resp = client.get('/rate-limited')
    assert resp.status_code == 200
    assert mock_request.call_count == 2


@patch('src.http_client.time.sleep')
@patch('src.http_client.httpx.request')
def test_exhausts_retries(mock_request, mock_sleep):
    mock_request.return_value = MagicMock(status_code=500)
    client = HttpClient('http://api.test', max_retries=2, base_delay=0.1)
    resp = client.get('/always-fails')
    assert resp.status_code == 500
    assert mock_request.call_count == 3  # initial + 2 retries


@patch('src.http_client.time.sleep')
@patch('src.http_client.httpx.request')
def test_exponential_backoff_delays(mock_request, mock_sleep):
    mock_request.return_value = MagicMock(status_code=503)
    client = HttpClient('http://api.test', max_retries=3, base_delay=1.0)
    client.get('/slow')
    delays = [call.args[0] for call in mock_sleep.call_args_list]
    assert delays == [1.0, 2.0, 4.0]  # base * 2^attempt


@patch('src.http_client.httpx.request')
def test_no_retry_on_client_error(mock_request):
    mock_request.return_value = MagicMock(status_code=404)
    client = HttpClient('http://api.test', max_retries=3)
    resp = client.get('/missing')
    assert resp.status_code == 404
    assert mock_request.call_count == 1  # no retries for 404
